mc.thePlayer.sendQueue.addToSendQueue(new C02PacketUseEntity(target, C02PacketUseEntity.Action.ATTACK));
// NoFriendDamage — cancel
if (event.getPacket() instanceof C02PacketUseEntity) {
  C02PacketUseEntity c02 = (C02PacketUseEntity) event.getPacket();
  if (c02.getAction() == C02PacketUseEntity.Action.ATTACK && isFriend(c02.getEntityFromWorld()))
    event.setCancelled(true);
}
// Criticals — inject offsets
if (event.getPacket() instanceof C02PacketUseEntity && ((C02PacketUseEntity)event.getPacket()).getAction() == ATTACK) {
  for (double offset : offsets)
    mc.thePlayer.sendQueue.addToSendQueue(new C04PacketPlayerPosition(x, y + offset, z, false));
}

